arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
PREFIX futuram: <https://www.purl.org/futuram#>
SELECT DISTINCT ?cls ?sup ?supLabel ?label WHERE {
  ?cls rdfs:subClassOf ?sup .
  OPTIONAL { ?sup rdfs:label ?supLabel }
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER( CONTAINS(LCASE(STR(?label)), "alalloy") ||
          CONTAINS(LCASE(STR(?supLabel)), "alalloy") ||
          CONTAINS(LCASE(STR(?supLabel)), "alloy") ||
          CONTAINS(LCASE(STR(?label)), "alloy") )
} LIMIT 100

