arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX dqv: <http://www.w3.org/ns/dqv#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX afn: <http://jena.apache.org/ARQ/function#>
SELECT ?whole ?kg
       (?itemMass * ?v1 * ?v2 AS ?kgValue)
       ((?v1 * ?v2) * ?itemMass * ?limit / 1.7320508 AS ?sigmaValue)
WHERE {
  ?whole a ?segClass .
  ?segClass rdfs:subClassOf <https://www.purl.org/futuram#elvBEV> .
  FILTER(STRENDS(STR(?whole), "_2020"))
  ?whole futuram:hasCompositionStatement ?st1 .
  ?st1 futuram:hasPartRelation ?pr1 .
  ?pr1 futuram:refersTo ?mid .
  ?mid a <https://www.purl.org/futuram#elvGeneralComponents> .
  ?pr1 futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v1 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
  ?mid futuram:hasCompositionStatement ?st2 .
  ?st2 futuram:hasPartRelation ?pr2 .
  ?pr2 futuram:refersTo ?leaf .
  ?leaf a/rdfs:subClassOf* <https://www.purl.org/futuram#5xxxAlAlloy> .
  ?pr2 futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v2 ; qudt:unit <http://qudt.org/vocab/unit/KiloGM-PER-KiloGM> ] .
  ?whole futuram:itemMass [ qudt:numericValue ?itemMass ; qudt:unit <http://qudt.org/vocab/unit/KiloGM> ] .
  # combine uncertainties of the two hops by RSS (in absolute)
  {
    SELECT ?pr1 (?limit AS ?limit1) WHERE {
      ?pr1 dqv:hasQualityMeasurement ?qm1 .
      ?qm1 dqv:isMeasurementOf ?dim1 .
      ?qm1 dqv:value ?s1 .
      {
        SELECT ?pr1 (SUM(?w*?s) AS ?wsum) WHERE {
          ?pr1 dqv:hasQualityMeasurement ?qm .
          ?qm dqv:isMeasurementOf ?dim .
          ?qm dqv:value ?s .
          BIND(IF(?dim = <https://www.purl.org/futuram#IntegrityScore>, 0.5, IF(?dim = <https://www.purl.org/futuram#TimelinessScore>, 1.5, 1.0)) AS ?w)
        } GROUP BY ?pr1
      }
      BIND(IF(?wsum < 7, 0.10, IF(?wsum < 9, 0.15, IF(?wsum < 10, 0.20, IF(?wsum < 14, 0.25, IF(?wsum < 15, 0.30, 0.35))))) AS ?limit)
    }
  }
  {
    SELECT ?pr2 (?limit AS ?limit2) WHERE {
      ?pr2 dqv:hasQualityMeasurement ?qm2 .
      ?qm2 dqv:isMeasurementOf ?dim2 .
      ?qm2 dqv:value ?s2 .
      {
        SELECT ?pr2 (SUM(?w*?s) AS ?wsum) WHERE {
          ?pr2 dqv:hasQualityMeasurement ?qm .
          ?qm dqv:isMeasurementOf ?dim .
          ?qm dqv:value ?s .
          BIND(IF(?dim = <https://www.purl.org/futuram#IntegrityScore>, 0.5, IF(?dim = <https://www.purl.org/futuram#TimelinessScore>, 1.5, 1.0)) AS ?w)
        } GROUP BY ?pr2
      }
      BIND(IF(?wsum < 7, 0.10, IF(?wsum < 9, 0.15, IF(?wsum < 10, 0.20, IF(?wsum < 14, 0.25, IF(?wsum < 15, 0.30, 0.35))))) AS ?limit)
    }
  }
  BIND(afn:sqrt((?limit1 * ?v1) * (?limit1 * ?v1) + (?limit2 * ?v2) * (?limit2 * ?v2)) / (?v1 + ?v2) AS ?sigmaRel)
}
ORDER BY DESC(?kgValue)
LIMIT 50

